INSERT OR IGNORE INTO innovation_theory (id, name_ja, name_en, definition, impact_summary, subfield, category, school_of_thought, era_start, schumpeter_layer, innovation_type, cognitive_mechanism, key_researchers, key_works, keywords_ja, keywords_en) VALUES
('inno_pol_251','プラットフォーム課税政策研究','Platform Taxation Policy Research','デジタルサービス税・売上配分税・最低法人税（グローバルミニマム税）等のプラットフォーム課税政策がイノベーション投資・立地選択・市場構造に与える影響を分析した研究群。OECD/G20 Pillar One/Two 合意の経済効果研究が含まれる。','デジタル経済の国際課税制度改革と税収配分の公平性設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','デジタル課税政策研究','2019','macro','policy','digital_taxation','["Devereux, M.P.", "Vella, J.", "Becker, J."]','["Devereux & Vella (2017) Taxing the digital economy", "OECD (2021) Pillar One and Two"]','デジタルサービス税,プラットフォーム課税,最低法人税,OECD Pillar','digital services tax,platform taxation,global minimum tax,OECD Pillar'),
('inno_pol_252','イノベーション政策の評価フレームワーク比較','Comparative Evaluation Framework for Innovation Policy','システム評価・プログラム評価・インパクト評価・プロセス評価など多様な評価フレームワークを比較し、STI政策の評価設計に最適なアプローチを提案した研究群。形成的評価と総括的評価の組み合わせ設計が重要テーマとなっている。','政府のSTI政策サイクルにおける評価機能の強化に実証的根拠を提供した。','measurement_policy_governance','D_directionality','政策評価方法論','2010','macro','policy','evaluation_framework','["Stern, E.", "Torrance, H.", "Kluve, J."]','["Stern (2015) Impact evaluation of innovation", "Kluve et al. (2016) Systematic review active labor"]','政策評価フレームワーク,形成的評価,総括的評価,STI評価','evaluation framework,formative evaluation,summative evaluation,STI evaluation'),
('inno_pol_253','デジタルインフラ投資政策の経済効果研究','Economic Effect Research on Digital Infrastructure Investment Policy','ブロードバンド・5G・データセンター・クラウドインフラへの公共投資がイノベーション・生産性・地域格差に与える効果を分析した研究群。DID・操作変数・空間計量経済学が方法論として用いられ、デジタルデバイドの是正効果も検討されている。','デジタルインフラ投資計画と地域振興政策の科学的根拠を提供した。','measurement_policy_governance','D_directionality','デジタルインフラ政策研究','2010','macro','policy','digital_infrastructure_investment','["Czernich, N.", "Falck, O.", "Kretschmer, T."]','["Czernich et al. (2011) Broadband infrastructure and economic growth", "Falck et al. (2014) Broadband access"]','ブロードバンド投資,デジタルインフラ,5G政策,デジタルデバイド','broadband investment,digital infrastructure,5G policy,digital divide'),
('inno_pol_254','科学コミュニケーション政策研究','Science Communication Policy Research','公衆の科学理解（PUS）・科学コミュニケーション政策・研究者の社会参加義務・オープンサイエンス普及を分析した研究群。欠落モデルから対話モデル・参加モデルへの転換と政策的含意が主要テーマとなっている。','科学技術広報政策と市民の科学受容政策設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','科学コミュニケーション研究','2003','macro','policy','science_communication_policy','["Bucchi, M.", "Trench, B.", "Wynne, B."]','["Bucchi (2004) Science in Society", "Wynne (1992) Misunderstood misunderstanding"]','科学コミュニケーション,PUS,欠落モデル,参加モデル','science communication,PUS,deficit model,participation model'),
('inno_pol_255','半導体産業政策の国際比較研究','International Comparative Research on Semiconductor Industry Policy','CHIPS Act（米国）・欧州半導体法・日本半導体復興計画・中国IC産業政策を比較分析した研究群。補助金規模・研究開発支援・人材育成・サプライチェーン再編への政策効果を検討した。','半導体産業政策設計とサプライチェーン安全保障に実証的根拠を提供した。','measurement_policy_governance','D_directionality','半導体産業政策研究','2020','macro','policy','semiconductor_policy','["Miller, C.", "Batzer, M.", "Shivakumar, S."]','["Miller (2022) Chip War", "CSIS (2023) Semiconductor policy comparison"]','半導体政策,CHIPS Act,欧州半導体法,サプライチェーン安全保障','semiconductor policy,CHIPS Act,European Chips Act,supply chain security'),
('inno_pol_256','イノベーション評価の書誌計量学','Bibliometrics for Innovation Evaluation','論文引用・共著ネットワーク・特許引用・科学-技術リンク（STL）の計量分析によるイノベーション評価手法を開発した研究群。ライデン宣言・DORA（研究評価に関するサンフランシスコ宣言）による書誌計量の適切な利用原則も議論されている。','研究評価・大学ランキング・科学技術政策の書誌計量的基盤構築に貢献した。','measurement_policy_governance','D_directionality','書誌計量・研究評価','2000','macro','policy','bibliometrics_evaluation','["Waltman, L.", "van Eck, N.J.", "Moed, H.F."]','["Moed (2005) Citation analysis in research evaluation", "Waltman & van Eck (2012) Field-normalized citation"]','書誌計量,引用分析,DORA,研究評価','bibliometrics,citation analysis,DORA,research evaluation'),
('inno_pol_257','自動化・AI政策と未来の雇用','Automation and AI Policy and the Future of Work','AI・ロボット・自動化による雇用構造変化に対応する政策（リスキリング・UBI・就業支援・教育改革）を分析した研究群。Acemoglu-Restrepoのタスクモデルを政策設計に応用した研究が含まれる。','雇用・社会保障政策の改革設計とAI経済移行管理に実証的根拠を提供した。','measurement_policy_governance','D_directionality','未来の仕事政策研究','2017','macro','policy','automation_work_policy','["Acemoglu, D.", "Autor, D.H.", "Daron, A."]','["Autor (2015) Why are there still so many jobs", "Acemoglu & Restrepo (2018) Robots and jobs"]','自動化政策,リスキリング,UBI,AI雇用','automation policy,reskilling,UBI,AI employment'),
('inno_pol_258','オープンイノベーション政策研究','Open Innovation Policy Research','産学官のオープンイノベーション促進政策（知財共有・コンソーシアム支援・オープンソース奨励）を分析した研究群。Chesbrough モデルの政策化と政府主導OIの効果・限界が主要テーマとなっている。','企業のオープンイノベーション戦略と政府の産業支援政策設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','オープンイノベーション政策研究','2010','macro','policy','open_innovation_policy','["Chesbrough, H.", "West, J.", "Bogers, M."]','["Chesbrough (2003) Open Innovation", "West & Bogers (2014) Leveraging external sources"]','オープンイノベーション政策,知財共有,コンソーシアム,産学官','open innovation policy,IP sharing,consortium,industry-academia-government'),
('inno_pol_259','医療イノベーション政策と患者アクセス','Healthcare Innovation Policy and Patient Access','新薬・医療機器・デジタルヘルスの承認加速制度（Fast Track・Breakthrough Therapy・SAKIGAKE）・アダプティブ承認・価値ベース評価を分析した研究群。イノベーション促進と患者アクセス・コストの政策的均衡が主要テーマとなっている。','医薬品規制制度改革と医療イノベーション生態系設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','医療イノベーション政策研究','2012','meso','policy','healthcare_innovation_policy','["Eichler, H.G.", "Bloechl-Daum, B.", "Abadie, E."]','["Eichler et al. (2012) Adaptive licensing", "EFPIA (2019) Patient access innovation"]','医療承認加速,アダプティブ承認,SAKIGAKE,患者アクセス','medical approval acceleration,adaptive licensing,SAKIGAKE,patient access'),
('inno_pol_260','エネルギー転換政策の政治経済学','Political Economy of Energy Transition Policy','再生可能エネルギー支援・化石燃料補助金廃止・電力市場自由化の政治的実現可能性と利害関係者ダイナミクスを分析した研究群。「ロックイン」・「座礁資産」・勝者連合形成が主要概念となっている。','エネルギー転換政策の政治的設計と利害調整戦略に実証的根拠を提供した。','measurement_policy_governance','D_directionality','エネルギー政策政治経済学','2015','macro','policy','energy_transition_political_economy','["Meckling, J.", "Strunz, S.", "Markard, J."]','["Meckling et al. (2015) Winning coalition for climate policy", "Markard et al. (2012) Sustainability transitions"]','エネルギー転換政策,再エネ支援,座礁資産,利害関係者','energy transition policy,renewable support,stranded assets,stakeholders'),
('inno_pol_261','グローバルバリューチェーンとイノベーション政策','Global Value Chains and Innovation Policy','多国籍企業のGVC（グローバルバリューチェーン）参加がホスト国のイノベーション能力向上に与える効果と、政策介入（ローカルコンテンツ要件・FDI規制・技術移転義務）の有効性を分析した研究群。','発展途上国の産業政策とGVC上位移動戦略に実証的根拠を提供した。','measurement_policy_governance','D_directionality','GVC・産業政策研究','2013','macro','policy','gvc_innovation_policy','["Gereffi, G.", "Humphrey, J.", "Sturgeon, T."]','["Gereffi et al. (2005) Governance of global value chains", "Sturgeon et al. (2008) Value chains automotive"]','GVC,グローバルバリューチェーン,ローカルコンテンツ,技術移転義務','GVC,global value chains,local content requirements,technology transfer obligation'),
('inno_pol_262','防衛イノベーション政策研究（デュアルユース）','Defense Innovation Policy Research: Dual-Use Technology','DARPA・防衛省研究開発・スウェーデン防衛研究庁等の防衛主導イノベーションが民間技術・産業に波及する「スピンオフ」効果と政策設計を分析した研究群。ステルス・GPS・インターネット等の歴史的事例と現代のAI・量子・宇宙での応用が研究されている。','防衛研究開発政策と軍民両用技術戦略の設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','防衛イノベーション政策研究','2005','macro','policy','defense_innovation_spinoff','["Stowsky, J.", "Mowery, D.C.", "Alic, J.A."]','["Mowery (2012) Defense as a source of innovation", "Stowsky (2004) Secrets to shields"]','防衛研究開発,スピンオフ,DARPA,デュアルユース','defense R&D,spinoff,DARPA,dual-use technology'),
('inno_pol_263','コモンズと知識ガバナンス','Commons and Knowledge Governance','Ostromのコモンズ管理理論を知識財・デジタルリソース・データ・遺伝資源へと拡張した研究群。知識コモンズの設計原則・フリーライダー問題・コモンズの悲劇と豊作を分析した。Creative Commons・オープンソースライセンスの政策的含意も議論されている。','デジタル知識政策と遺伝資源ガバナンス（名古屋議定書）設計に理論的根拠を提供した。','measurement_policy_governance','D_directionality','知識コモンズ研究','2007','macro','policy','knowledge_commons','["Hess, C.", "Ostrom, E.", "Benkler, Y."]','["Hess & Ostrom (2007) Understanding knowledge as a commons", "Benkler (2006) Wealth of networks"]','知識コモンズ,Ostrom,Creative Commons,デジタルコモンズ','knowledge commons,Ostrom,Creative Commons,digital commons'),
('inno_pol_264','薬事規制改革とイノベーション','Pharmaceutical Regulatory Reform and Innovation','FDA・EMA・PMDA等の医薬品規制当局の審査制度改革（リアルワールドエビデンス・マスタープロトコル・バスケット試験）がイノベーション速度・患者アウトカムに与える影響を分析した研究群。','医薬品規制制度の近代化政策と規制科学教育に実証的根拠を提供した。','measurement_policy_governance','D_directionality','規制科学研究','2015','macro','policy','regulatory_reform_pharma','["Eichler, H.G.", "Oye, K.", "Woodcock, J."]','["Eichler et al. (2015) Adaptive pathways", "Woodcock & LaVange (2017) Master protocols"]','FDA規制改革,リアルワールドエビデンス,マスタープロトコル,規制科学','FDA regulatory reform,real-world evidence,master protocol,regulatory science'),
('inno_pol_265','スマートシティ政策の国際比較研究','International Comparative Research on Smart City Policy','スマートシティ計画（シンガポール・バルセロナ・東京・ドバイ）の政策設計・ガバナンス・成果を比較分析した研究群。データガバナンス・市民参加・ベンダーロックイン・SDGs整合が主要テーマとなっている。','スマートシティ政策設計と都市デジタル変革戦略に実証的根拠を提供した。','measurement_policy_governance','D_directionality','スマートシティ政策研究','2015','macro','policy','smart_city_policy','["Neirotti, P.", "Caragliu, A.", "Albino, V."]','["Neirotti et al. (2014) Smart cities overview", "Caragliu et al. (2011) Smart cities in Europe"]','スマートシティ政策,都市DX,データガバナンス,SDGs都市','smart city policy,urban DX,data governance,SDGs cities'),
('inno_pol_266','社会技術転換政策研究（MLP・TIS）','Socio-Technical Transition Policy Research: MLP and TIS','マルチレベルパースペクティブ（MLP）と技術革新システム（TIS）の視点から持続可能な転換への政策介入を分析した研究群。ニッチ管理・レジーム変革・ランドスケープ圧力の政策活用が主要テーマとなっている。','エネルギー・モビリティ・農業の持続可能な転換政策設計に理論的根拠を提供した。','measurement_policy_governance','D_directionality','転換政策研究','2010','macro','policy','transition_governance','["Kern, F.", "Smith, A.", "Raven, R."]','["Kern & Smith (2008) Restructuring energy systems", "Raven et al. (2012) Transitions and strategic niche management"]','転換政策,MLP,TIS,ニッチ管理','transition policy,MLP,TIS,niche management'),
('inno_pol_267','科学顧問制度と政策決定','Science Advisory Systems and Policy Making','政府の科学顧問機関（UK CSA・米国PCAST・EU SAM・内閣府CSTI）の設計・機能・政策影響を比較分析した研究群。証拠に基づく政策立案（EBP）・科学的不確実性の政策への伝達・政治的圧力からの独立性が主要テーマとなっている。','政府の科学技術助言機能の制度設計と民主的説明責任の確保に実証的根拠を提供した。','measurement_policy_governance','D_directionality','科学顧問研究','2005','macro','policy','science_advisory','["Gluckman, P.", "Bijker, W.", "Jasanoff, S."]','["Gluckman (2014) Policy: The art of science advice", "Jasanoff (1990) Fifth Branch science advisors"]','科学顧問,EBP,PCAST,CSTI','science advisory,EBP,PCAST,CSTI'),
('inno_pol_268','イノベーション政策の分権化と地域ガバナンス','Decentralization of Innovation Policy and Regional Governance','国・州・地方自治体間のイノベーション政策権限配分とその成果を分析した研究群。地域固有の知識・産業構造への適応と政策の断片化リスクのトレードオフが主要テーマとなっている。連邦制国家（米国・ドイツ・スイス）と中央集権国家（日本・フランス）の比較研究が含まれる。','地域イノベーション政策設計と科学技術行政の分権化改革に実証的根拠を提供した。','measurement_policy_governance','D_directionality','地域イノベーションガバナンス研究','2007','macro','policy','regional_innovation_governance','["Cooke, P.", "Tödtling, F.", "Trippl, M."]','["Cooke (2001) Regional innovation systems", "Tödtling & Trippl (2005) One size fits all"]','地域イノベーション政策,分権化,地域ガバナンス,RIS','regional innovation policy,decentralization,regional governance,RIS'),
('inno_pol_269','社会的弱者とイノベーション：インクルーシブイノベーション政策','Vulnerable Groups and Innovation: Inclusive Innovation Policy','貧困層・障害者・農村住民向けの「ボトムオブピラミッド（BOP）」・アフォーダブルイノベーション・適正技術政策を分析した研究群。Prahalad のBOP論を政策に適用し、インクルーシブイノベーションの促進制度設計が検討されている。','開発途上国支援政策と先進国の社会的包摂イノベーション戦略に実証的根拠を提供した。','measurement_policy_governance','D_directionality','インクルーシブイノベーション政策研究','2008','macro','policy','inclusive_innovation_policy','["Prahalad, C.K.", "George, G.", "Prabhu, J."]','["Prahalad (2004) Fortune at the bottom of the pyramid", "George et al. (2012) Inclusive innovation"]','インクルーシブイノベーション,BOP,適正技術,社会的包摂','inclusive innovation,BOP,appropriate technology,social inclusion'),
('inno_pol_270','研究不正対策と研究誠実性政策','Research Misconduct Countermeasures and Research Integrity Policy','捏造・改ざん・剽窃（FFP）対策・研究倫理教育・調査機関設計・データ公開義務化を分析した研究群。Retraction Watch分析・p-hacking問題・再現性危機への政策対応が主要テーマとなっている。','研究誠実性ガバナンスと科学への社会的信頼維持に実証的根拠を提供した。','measurement_policy_governance','D_directionality','研究誠実性政策研究','2010','macro','policy','research_integrity_policy','["Fanelli, D.", "Nosek, B.A.", "Steneck, N.H."]','["Fanelli (2009) How many scientists fabricate", "Steneck (2006) Research integrity"]','研究不正,FFP,研究誠実性,再現性危機','research misconduct,FFP,research integrity,replication crisis'),
('inno_pol_271','特許トロール問題とパテントポリシー','Patent Troll Problem and Patent Policy','非実施主体（NPE・PAE）による特許濫用・パテントホールドアップ・特許裁判地ショッピングの問題と政策対応（IPR手続き・特許品質向上・損害賠償改革）を分析した研究群。','イノベーション阻害要因としての特許濫用政策対応と知的財産制度改革に実証的根拠を提供した。','measurement_policy_governance','D_directionality','特許制度改革研究','2007','macro','policy','patent_troll_policy','["Bessen, J.", "Meurer, M.J.", "Lemley, M.A."]','["Bessen & Meurer (2008) Patent failure", "Lemley & Shapiro (2007) Patent holdup"]','パテントトロール,NPE,パテントホールドアップ,特許改革','patent troll,NPE,patent holdup,patent reform'),
('inno_pol_272','公的研究機関の産学官連携評価指標','Evaluation Indicators for Public Research Institution-Industry-Government Collaboration','大学・国立研究所の産学官連携成果（共同研究費・ライセンス収入・スピンオフ数・人材移動）の計測・評価指標を開発した研究群。TLO業績指標・AUTM調査・ASTP調査の方法論的問題も検討されている。','研究機関の社会的貢献評価と産学連携政策設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','産学連携評価研究','2005','macro','policy','tti_evaluation_metrics','["Siegel, D.S.", "Waldman, D.", "Link, A.N."]','["Siegel et al. (2003) Commercial knowledge transfers from universities", "Link & Siegel (2005) Univeristy-based technology transfer"]','産学官連携評価,TLO,ライセンス収入,スピンオフ数','university-industry-government collaboration evaluation,TLO,license income,spinoff count'),
('inno_pol_273','AIセーフティ政策研究','AI Safety Policy Research','AIの整合性・堅牢性・解釈可能性・アライメントに関する技術的安全性研究と政策立法（EU AI Act・米国大統領令13859等）の設計を分析した研究群。カタストロフィックリスク・AGI移行のガバナンスも新興テーマとなっている。','AI規制政策の安全性要件設計と国際AI安全協力に実証的根拠を提供した。','measurement_policy_governance','D_directionality','AI安全政策研究','2020','macro','policy','ai_safety_policy','["Russell, S.", "Hadfield-Menell, D.", "Irving, G."]','["Russell (2019) Human Compatible", "Hadfield-Menell (2019) Inverse reward design"]','AIセーフティ,整合性,解釈可能性,カタストロフィックリスク','AI safety,alignment,interpretability,catastrophic risk'),
('inno_pol_274','リビングラボ政策と市民イノベーション','Living Labs Policy and Citizen Innovation','リビングラボ（実環境実証場）・シビックテック・市民科学・共創型イノベーション政策の設計と効果を分析した研究群。EUのENoLL（欧州リビングラボネットワーク）の評価と自治体主導リビングラボの費用対効果が研究されている。','市民参加型イノベーション政策と都市実証実験制度の設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','リビングラボ・市民イノベーション研究','2006','meso','policy','living_lab_policy','["Almirall, E.", "Lee, M.", "Wareham, J."]','["Almirall & Wareham (2011) Living Labs", "Lee et al. (2012) Living Labs innovation"]','リビングラボ,シビックテック,市民イノベーション,ENoLL','living lab,civic tech,citizen innovation,ENoLL'),
('inno_pol_275','量子コンピューティング政策の国際比較','International Comparison of Quantum Computing Policy','米国・EU・中国・日本・英国等の量子技術国家戦略を比較分析した研究群。量子ロードマップ・公共投資規模・産学連携・輸出規制・量子人材政策が比較軸となっている。','量子技術政策の設計改善と国際競争環境の把握に実証的根拠を提供した。','measurement_policy_governance','D_directionality','量子技術政策研究','2018','macro','policy','quantum_policy_comparison','["Krelina, M.", "Raymer, M.G.", "Grumbling, E."]','["Krelina (2021) Quantum technology for military", "NIST (2022) Quantum initiative report"]','量子技術政策,国家量子戦略,量子ロードマップ,量子人材','quantum technology policy,national quantum strategy,quantum roadmap,quantum talent'),
('inno_pol_276','フロンティア研究投資の根拠と設計','Rationale and Design of Frontier Research Investment','基礎研究・キュリオシティ駆動型研究への公的投資根拠・適切な配分メカニズム・インパクト計測の難しさを論じた研究群。ブッシュ報告「Science: The Endless Frontier」以降の論争と現代的再解釈が含まれる。','国家科学財団・科学技術振興機構等の基礎研究投資政策に理論的根拠を提供した。','measurement_policy_governance','D_directionality','基礎研究政策研究','2000','macro','policy','frontier_research_investment','["Bush, V.", "Stokes, D.E.", "Lane, J."]','["Bush (1945) Science: The Endless Frontier", "Stokes (1997) Pasteur''s Quadrant"]','フロンティア研究,Pasteur象限,基礎研究投資,ブッシュ報告','frontier research,Pasteur quadrant,basic research investment,Bush report'),
('inno_pol_277','ブルーオーシャン戦略と産業政策の接点','Blue Ocean Strategy and Industrial Policy Interface','Kim & Mauborgne のブルーオーシャン戦略を政府の産業政策設計に応用した研究群。「競争なき市場空間」の政策的創出・価値革新支援・既存産業の価値曲線変革を促す政策手段を分析した。','産業振興政策の新規市場創造促進設計に理論的根拠を提供した。','measurement_policy_governance','D_directionality','市場創造政策研究','2010','meso','policy','blue_ocean_policy','["Kim, W.C.", "Mauborgne, R.", "Lim, M.K."]','["Kim & Mauborgne (2005) Blue Ocean Strategy", "Lim et al. (2021) Blue ocean policy"]','ブルーオーシャン,価値革新,産業政策,新規市場創造','blue ocean,value innovation,industrial policy,new market creation'),
('inno_pol_278','技術スタンダード化政策研究（ICT・クリーンテック）','Technology Standardization Policy Research: ICT and Clean Tech','ICT・再生可能エネルギー・電動車充電・5G等の技術標準化プロセスへの政府関与とイノベーションへの影響を分析した研究群。標準設定競争・FRAND（公正・合理的・非差別的）ライセンス・標準必須特許（SEP）政策が主要テーマとなっている。','技術標準政策設計と国際標準競争への政府戦略に実証的根拠を提供した。','measurement_policy_governance','D_directionality','技術標準政策研究','2005','macro','policy','standardization_policy','["Blind, K.", "Bekkers, R.", "Teece, D.J."]','["Blind (2004) Economics of standards", "Bekkers et al. (2011) SEP policy"]','技術標準,SEP,FRAND,標準設定競争','technology standards,SEP,FRAND,standard setting competition'),
('inno_pol_279','炭素国境調整措置（CBAM）とイノベーション政策','Carbon Border Adjustment Mechanism and Innovation Policy','EU CBMAのような炭素国境調整措置が輸入国の低炭素技術投資・イノベーション・貿易構造に与える影響を分析した研究群。カーボンリーケージ対策としての有効性とWTO整合性が主要テーマとなっている。','気候変動国際政策とグリーン産業政策の整合設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','炭素国境調整研究','2021','macro','policy','cbam_innovation','["Mehling, M.A.", "van Asselt, H.", "Das, K."]','["Mehling et al. (2019) Designing border carbon adjustments", "EU Commission (2021) CBAM proposal"]','CBAM,炭素国境調整,カーボンリーケージ,WTO整合','CBAM,carbon border adjustment,carbon leakage,WTO compatibility'),
('inno_pol_280','ヘルステックエコシステムのガバナンス研究','Health Tech Ecosystem Governance Research','AIヘルス・遠隔医療・デジタル治療薬（DTx）・ウェアラブル医療機器のエコシステムをガバナンスする規制フレームワーク・リンバーガバナンス・適応型規制を分析した研究群。FDA Digital Health Center・CE-MDR改訂等の実施評価が含まれる。','ヘルステック規制の俊敏性と安全性の均衡設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','ヘルステックガバナンス研究','2018','meso','policy','healthtech_governance','["Gerke, S.", "Minssen, T.", "Cohen, G.I."]','["Gerke et al. (2020) Regulatory approaches AI medical", "FDA (2021) Action plan AI/ML SaMD"]','ヘルステックガバナンス,DTx,AI医療規制,FDA SaMD','healthtech governance,DTx,AI medical regulation,FDA SaMD'),
('inno_pol_281','デジタル貿易政策研究','Digital Trade Policy Research','電子商取引の国際ルール（CPTPP電子商取引章・RCEP・WTO電子商取引交渉）・クロスボーダーデータフロー・データローカライゼーション要件のイノベーション・貿易効果を分析した研究群。','デジタル通商政策とデータ経済の国際ガバナンス設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','デジタル貿易政策研究','2017','macro','policy','digital_trade_policy','["Burri, M.", "Mattoo, A.", "Meltzer, J.P."]','["Burri (2021) Digital trade agreements", "Mattoo & Meltzer (2018) International data flows"]','デジタル貿易,クロスボーダーデータフロー,CPTPP,WTO電子商取引','digital trade,cross-border data flows,CPTPP,WTO e-commerce'),
('inno_pol_282','イノベーション政策の評価における反事実分析','Counterfactual Analysis in Innovation Policy Evaluation','「政策がなかった場合」のシナリオを構築し、政策効果を因果的に推定する方法論の革新を論じた研究群。合成コントロール法・マッチング・RDD・IVなど準実験的手法のSTI政策評価への適用事例が体系化されている。','政策評価の厳密性向上と政府の政策学習サイクル強化に実証的根拠を提供した。','measurement_policy_governance','D_directionality','政策評価方法論','2012','macro','policy','counterfactual_policy','["Abadie, A.", "Diamond, A.", "Hainmueller, J."]','["Abadie et al. (2010) Synthetic control methods", "Hainmueller (2012) Entropy balancing"]','反事実分析,合成コントロール法,RDD,政策評価手法','counterfactual analysis,synthetic control,RDD,policy evaluation methods'),
('inno_pol_283','イノベーション政策のアジャイル化研究','Agilification of Innovation Policy Research','STI政策の計画・実施・評価サイクルを短縮し、実証と学習を高速化する「アジャイル政策立案」の概念と事例を分析した研究群。政策実験・パイロット→スケール・ポリシーラボの活用が主要テーマとなっている。','政府のSTI政策立案プロセスの近代化と省庁横断協働の改善に実証的根拠を提供した。','measurement_policy_governance','D_directionality','アジャイル政策研究','2018','macro','policy','agile_policy_making','["Hallsworth, M.", "Halpern, D.", "Nesta Labs"]','["Hallsworth et al. (2018) EAST behavioural insights", "Nesta (2019) Experimental government"]','アジャイル政策,ポリシーラボ,政策実験,行動インサイト','agile policy,policy lab,policy experiment,behavioural insights'),
('inno_pol_284','デジタルID・電子政府ガバナンス研究','Digital ID and E-Government Governance Research','国民IDデジタル化・マイナンバー・エストニアe-Estonia等の電子政府ガバナンスモデルを分析した研究群。相互運用性・プライバシー・デジタル包摂・政府データの二次利用ルールが主要テーマとなっている。','行政デジタル変革政策と電子政府国際比較に実証的根拠を提供した。','measurement_policy_governance','D_directionality','電子政府ガバナンス研究','2012','macro','policy','digital_id_gov','["Dutil, P.A.", "Howard, C.", "Langford, J."]','["Dutil et al. (2007) Rethinking government-public", "Janssen et al. (2012) Benefits adoption barriers e-government"]','デジタルID,マイナンバー,e-Estonia,電子政府ガバナンス','digital ID,My Number,e-Estonia,e-government governance'),
('inno_pol_285','イノベーション産業集積の自然実験研究','Natural Experiment Research on Innovation Agglomeration','産業集積の因果効果を道路建設・空港立地・偶発的歴史的事件を自然実験として用いて推定した研究群。集積外部性の識別とソーティング効果との分離が主要方法論的課題となっている。','産業集積政策・経済特区・科学技術特区の設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','集積経済研究（自然実験）','2006','macro','policy','agglomeration_natural_experiment','["Greenstone, M.", "Hornbeck, R.", "Moretti, E."]','["Greenstone et al. (2010) Identifying agglomeration spillovers", "Moretti (2004) Workers education spillovers"]','産業集積自然実験,集積外部性,経済特区,ソーティング効果','agglomeration natural experiment,agglomeration externalities,special economic zone,sorting effects'),
('inno_pol_286','国家データ戦略とイノベーション政策','National Data Strategy and Innovation Policy','国家データ戦略（UK National Data Strategy・EU Data Strategy・日本データ戦略）がデータ駆動型イノベーションに与える効果を分析した研究群。データスペース・データガバナンス法・データアクト等のEUデータ法制との整合が主要テーマとなっている。','データエコノミー政策とデジタル産業競争力戦略に実証的根拠を提供した。','measurement_policy_governance','D_directionality','国家データ戦略研究','2020','macro','policy','national_data_strategy','["EU Commission", "DCMS", "Duch-Brown, N."]','["EU (2020) European data strategy", "DCMS (2020) UK National Data Strategy"]','国家データ戦略,データスペース,データガバナンス法,データアクト','national data strategy,data spaces,Data Governance Act,Data Act'),
('inno_pol_287','脱炭素産業政策の設計原則研究','Design Principles of Decarbonization Industrial Policy','IRA（インフレ削減法）・欧州グリーンディール産業計画・日本GX戦略等の脱炭素産業政策の設計原則と期待効果を分析した研究群。技術補助・カーボンプライシング・グリーン調達の最適組み合わせが主要テーマとなっている。','脱炭素移行の産業政策設計と国際競争公正性の維持に実証的根拠を提供した。','measurement_policy_governance','D_directionality','脱炭素産業政策研究','2022','macro','policy','decarbonization_industrial_policy','["Grubler, A.", "Wilson, C.", "Meckling, J."]','["IRA (2022) design analysis", "Meckling & Nahm (2022) The power of green industrial policy"]','IRA,欧州グリーンディール,GX戦略,脱炭素産業政策','IRA,European Green Deal,GX strategy,decarbonization industrial policy'),
('inno_pol_288','デジタル通貨・フィンテック規制政策研究','Digital Currency and Fintech Regulatory Policy Research','フィンテックサンドボックス・CBDC規制・暗号資産規制（MiCA）・オープンバンキング法制の設計と効果を分析した研究群。金融安定・消費者保護・イノベーション促進の三角トレードオフが主要テーマとなっている。','デジタル金融規制設計と国際的な金融規制調和に実証的根拠を提供した。','measurement_policy_governance','D_directionality','フィンテック規制政策研究','2016','macro','policy','fintech_regulation_policy','["Zetzsche, D.A.", "Arner, D.W.", "Buckley, R.P."]','["Zetzsche et al. (2020) RegTech ecosystem", "Arner et al. (2016) FinTech RegTech"]','フィンテック規制,MiCA,CBDC規制,RegTech','fintech regulation,MiCA,CBDC regulation,RegTech'),
('inno_pol_289','ポスト成長・脱成長論とイノベーション政策','Post-Growth and Degrowth Theory and Innovation Policy','GDP成長を目標とする従来のイノベーション政策を批判し、ウェルビーイング・ドーナツ経済・生態的限界を中心に据えた政策パラダイムを論じた研究群。Hickelらの脱成長論とイノベーション政策の再設計を検討した。','持続可能な福祉政策と生態的経済政策の設計に理論的根拠を提供した。','measurement_policy_governance','D_directionality','脱成長・ウェルビーイング政策研究','2017','macro','policy','degrowth_innovation','["Hickel, J.", "Kallis, G.", "Raworth, K."]','["Hickel (2020) Less is More", "Raworth (2017) Doughnut Economics"]','脱成長,ドーナツ経済,ウェルビーイング政策,生態的限界','degrowth,doughnut economics,wellbeing policy,ecological limits'),
('inno_pol_290','量子暗号と情報セキュリティ政策','Quantum Cryptography and Information Security Policy','量子コンピュータによる既存暗号（RSA・楕円曲線）の破綻リスクへの政府・企業の政策対応（ポスト量子暗号移行・量子セーフインフラ計画）を分析した研究群。NISTポスト量子暗号標準化・国際移行ロードマップが主要テーマとなっている。','国家サイバーセキュリティ戦略の量子移行計画設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','量子セキュリティ政策研究','2020','macro','policy','post_quantum_policy','["Mosca, M.", "Bernstein, D.J.", "Lange, T."]','["Mosca (2018) Cybersecurity in quantum computing era", "NIST (2024) Post-quantum standards"]','ポスト量子暗号,量子セキュリティ政策,NISTポスト量子,量子移行','post-quantum cryptography,quantum security policy,NIST PQC,quantum migration'),
('inno_pol_291','ソーシャルメディア規制とイノベーション','Social Media Regulation and Innovation','プラットフォームコンテンツ規制（DSA・NetzDG・豪州オンライン安全法）がコンテンツイノベーション・言論の自由・表現技術発展に与える影響を分析した研究群。「過剰規制によるチリング効果」と「規制不足による害悪」の政策的均衡が主要テーマとなっている。','プラットフォームガバナンス政策と次世代コンテンツサービス設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','プラットフォームコンテンツ規制研究','2018','macro','policy','social_media_regulation','["Heldt, A.", "Helberger, N.", "Leerssen, P."]','["Heldt (2019) Reading between the lines NetzDG", "Helberger et al. (2018) Governing online platforms"]','ソーシャルメディア規制,DSA,NetzDG,コンテンツガバナンス','social media regulation,DSA,NetzDG,content governance'),
('inno_pol_292','マクロ経済政策とイノベーション：金融政策の役割','Macroeconomic Policy and Innovation: The Role of Monetary Policy','金利・量的緩和・流動性環境がスタートアップ資金調達・VC投資・R&D支出・イノベーション指向投資に与える影響を分析した研究群。低金利時代と利上げ後のイノベーションエコシステムの変容が主要テーマとなっている。','中央銀行政策とイノベーション生態系への副次的影響の把握に実証的根拠を提供した。','measurement_policy_governance','D_directionality','マクロ経済・イノベーション政策研究','2015','macro','policy','monetary_policy_innovation','["Nanda, R.", "Rhodes-Kropf, M.", "Caballero, R.J."]','["Nanda & Rhodes-Kropf (2013) Investment cycles VC", "Caballero et al. (2008) Zombie firms"]','金融政策,低金利,VC投資,イノベーション資金','monetary policy,low interest rates,VC investment,innovation finance'),
('inno_pol_293','国際技術格差と技術移転政策','International Technology Gap and Technology Transfer Policy','先進国-途上国間の技術格差を計測し、FDI・ライセンス・技術援助・留学生の経路での技術移転効果を分析した研究群。キャッチアップ速度・技術吸収能力・模倣政策とイノベーション政策の政策移行が主要テーマとなっている。','途上国の産業技術政策と国際開発援助のイノベーション支援設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','技術格差・移転政策研究','2003','macro','policy','tech_gap_transfer','["Fagerberg, J.", "Verspagen, B.", "Castellacci, F."]','["Fagerberg & Verspagen (2002) Technology-gaps, innovation-diffusion", "Castellacci (2008) Technological paradigms"]','技術格差,技術移転,キャッチアップ,技術吸収能力','technology gap,technology transfer,catch-up,absorptive capacity'),
('inno_pol_294','医療AI規制フレームワークの国際比較','International Comparison of Medical AI Regulatory Frameworks','FDA AI/ML SaMD政策・CE-MDR・日本薬機法改正等の医療AI規制フレームを比較分析した研究群。プレmarket/ポストmarket監視・継続的学習AIのロックフリー問題・臨床バリデーション要件の国際差が主要テーマとなっている。','医療AI製品の国際市場参入戦略と規制調和交渉に実証的根拠を提供した。','measurement_policy_governance','D_directionality','医療AI規制研究','2019','macro','policy','medical_ai_regulation','["Topol, E.J.", "Char, D.S.", "Shah, N.H."]','["FDA (2021) AI/ML SaMD action plan", "Char et al. (2018) Identifying ethical considerations AI healthcare"]','医療AI規制,FDA SaMD,CE-MDR,薬機法改正','medical AI regulation,FDA SaMD,CE-MDR,Japan pharmaceuticals law'),
('inno_pol_295','研究評価の改革運動（DORA・Leiden宣言）','Research Evaluation Reform Movements: DORA and Leiden Manifesto','San Francisco宣言（DORA）・ライデン宣言・CoARA（研究評価改革連合）・研究評価のメトリクス偏重批判を分析した研究群。インパクトファクター依存・ジャーナルランキング廃止・評価多様化への政策的含意が主要テーマとなっている。','大学・研究機関の研究者評価制度改革と科学技術政策の評価基準見直しに貢献した。','measurement_policy_governance','D_directionality','研究評価改革研究','2013','macro','policy','research_evaluation_reform','["Hicks, D.", "Wouters, P.", "Waltman, L."]','["Hicks et al. (2015) Leiden Manifesto", "DORA (2013) San Francisco Declaration"]','DORA,ライデン宣言,研究評価改革,インパクトファクター','DORA,Leiden Manifesto,research evaluation reform,impact factor'),
('inno_pol_296','サイバーセキュリティ政策とイノベーションエコシステム','Cybersecurity Policy and Innovation Ecosystem','NISTサイバーセキュリティフレームワーク・EU NIS2指令・日本サイバーセキュリティ戦略等のサイバーセキュリティ規制がイノベーション生態系・スタートアップ・DXに与える影響を分析した研究群。セキュリティイノベーションの「パラドックス」も議論されている。','企業のサイバーセキュリティ投資と政府の規制設計の均衡に実証的根拠を提供した。','measurement_policy_governance','D_directionality','サイバーセキュリティ政策研究','2014','macro','policy','cybersecurity_policy_ecosystem','["NIST", "EU ENISA", "Deibert, R.J."]','["NIST (2018) Cybersecurity Framework", "EU (2022) NIS2 directive"]','サイバーセキュリティ政策,NIS2,NIST CSF,セキュリティイノベーション','cybersecurity policy,NIS2,NIST CSF,security innovation'),
('inno_pol_297','クリエイティブ産業政策とイノベーション','Creative Industry Policy and Innovation','映画・音楽・ゲーム・ファッション・建築等クリエイティブ産業の育成政策（税控除・著作権制度・スタジオ補助・都市クリエイティブクラスター）を分析した研究群。Floridaのクリエイティブクラス論への批判的検討も含まれる。','クリエイティブ産業振興政策と文化的なイノベーション生態系設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','クリエイティブ産業政策研究','2007','macro','policy','creative_industry_policy','["Florida, R.", "Howkins, J.", "Caves, R.E."]','["Florida (2002) Rise of the Creative Class", "Howkins (2001) Creative Economy"]','クリエイティブ産業,クリエイティブクラス,文化産業政策,都市クラスター','creative industry,creative class,cultural industry policy,urban cluster'),
('inno_pol_298','エコイノベーション計測の方法論研究','Eco-Innovation Measurement Methodology Research','環境技術特許・グリーンR&D支出・環境製品サービス売上等エコイノベーション指標の計測・集計方法を開発した研究群。OECD・EEA・Eurostatのエコイノベーション統計フレームワークの評価も含まれる。','環境イノベーション政策評価の数量的基盤構築に貢献した。','measurement_policy_governance','D_directionality','エコイノベーション計測研究','2009','macro','policy','eco_innovation_measurement','["Rennings, K.", "Kemp, R.", "Bergmann, A."]','["Rennings (2000) Redefining eco-innovation", "Kemp & Pearson (2007) MEPI project"]','エコイノベーション計測,グリーン特許,環境R&D,MEPI','eco-innovation measurement,green patents,environmental R&D,MEPI'),
('inno_pol_299','フードシステムイノベーション政策研究','Food System Innovation Policy Research','持続可能な食料システムへの転換を促す政策（農業補助金改革・フードテック支援・短縮サプライチェーン・食品廃棄削減規制）を分析した研究群。農業政策とイノベーション政策の統合設計が重要テーマとなっている。','食料安全保障政策と持続可能な農食業転換に実証的根拠を提供した。','measurement_policy_governance','D_directionality','食料システム政策研究','2015','macro','policy','food_system_innovation_policy','["Foresight", "IPES-Food", "EAT-Lancet Commission"]','["IPES-Food (2015) New science sustainable food", "EAT-Lancet (2019) Food in the Anthropocene"]','フードシステムイノベーション,農業補助金改革,フードテック政策,食品廃棄削減','food system innovation,agricultural subsidy reform,foodtech policy,food waste reduction'),
('inno_pol_300','AIと民主主義：選挙・情報操作への政策対応','AI and Democracy: Policy Responses to Elections and Information Manipulation','生成AIによるディープフェイク・マイクロターゲティング・フィルターバブルが民主主義プロセスに与えるリスクへの政策対応（AI生成コンテンツ表示義務・選挙広告透明性規制・リテラシー教育）を分析した研究群。','民主主義制度のデジタル強靭化とAI規制の民主的正当性設計に実証的根拠を提供した。','measurement_policy_governance','D_directionality','AI民主主義政策研究','2020','macro','policy','ai_democracy_policy','["Persily, N.", "Tucker, J.A.", "Guriev, S."]','["Persily & Tucker (2020) Social media and democracy", "EU Commission (2022) AI electoral integrity"]','AI民主主義,ディープフェイク,選挙規制,情報操作','AI democracy,deepfakes,election regulation,information manipulation');
